content.content:
  1→import { spawn, type ChildProcess } from "node:child_process";
  2→import { createOpencodeClient } from "@opencode-ai/sdk";
  3→import type { OpencodeConfig } from "./config-builder";
  4→import type { OpenCodeHandle } from "./session-lifecycle";
  5→
  6→// ---------------------------------------------------------------------------
  7→// Port allocation — find a free port by binding to 0
  8→// ---------------------------------------------------------------------------
  9→
 10→async function findFreePort(): Promise<number> {
 11→  const { createServer } = await import("node:net");
 12→  return new Promise((resolve, reject) => {
 13→    const srv = createServer();
 14→    srv.listen(0, "127.0.0.1", () => {
 15→      const addr = srv.address();
 16→      if (!addr || typeof addr === "string") {
 17→        srv.close();
 18→        reject(new Error("Failed to allocate port"));
 19→        return;
 20→      }
 21→      const port = addr.port;
 22→      srv.close(() => resolve(port));
 23→    });
 24→    srv.on("error", reject);
 25→  });
 26→}
 27→
 28→// ---------------------------------------------------------------------------
 29→// SDK Config translation
 30→// ---------------------------------------------------------------------------
 31→
 32→type SdkConfig = {
 33→  model?: string;
 34→  mcp?: Record<string, { type: "remote"; url: string; headers?: Record<string, string> }>;
 35→  agent?: {
 36→    build?: {
 37→      permission?: {
 38→        edit?: "allow" | "ask" | "deny";
 39→        bash?: "allow" | "ask" | "deny";
 40→        webfetch?: "allow" | "ask" | "deny";
 41→      };
 42→    };
 43→  };
 44→};
 45→
 46→function toSdkConfig(config: OpencodeConfig): SdkConfig {
 47→  const mcp: SdkConfig["mcp"] = {};
 48→  for (const [name, server] of Object.entries(config.mcpServers)) {
 49→    mcp[name] = {
 50→      type: "remote" as const,
 51→      url: server.url,
 52→      headers: server.headers,
 53→    };
 54→  }
 55→
 56→  const permissionMap: Record<string, "allow" | "ask" | "deny"> = {};
 57→  for (const perm of config.permissions.autoApprove) {
 58→    permissionMap[perm] = "allow";
 59→  }
 60→
 61→  return {
 62→    model: `${config.model.provider}/${config.model.model}`,
 63→    mcp,
 64→    agent: {
 65→      build: {
 66→        permission: {
 67→          edit: permissionMap["edit"] ?? permissionMap["write"] ?? "allow",
 68→          bash: permissionMap["bash"] ?? "allow",
 69→          webfetch: permissionMap["webfetch"] ?? "deny",
 70→        },
 71→      },
 72→    },
 73→  };
 74→}
 75→
 76→// ---------------------------------------------------------------------------
 77→// Start OpenCode server process in the worktree directory
 78→// ---------------------------------------------------------------------------
 79→
 80→const SERVER_START_TIMEOUT_MS = 15_000;
 81→
 82→function startServerProcess(
 83→  port: number,
 84→  hostname: string,
 85→  sdkConfig: SdkConfig,
 86→  worktreePath: string,
 87→  signal: AbortSignal,
 88→): Promise<{ proc: ChildProcess; url: string }> {
 89→  const args = ["serve", `--hostname=${hostname}`, `--port=${port}`];
 90→  const proc = spawn("opencode", args, {
 91→    cwd: worktreePath,
 92→    signal,
 93→    env: {
 94→      ...process.env,
 95→      OPENCODE_CONFIG_CONTENT: JSON.stringify(sdkConfig),
 96→    },
 97→  });
 98→
 99→  return new Promise((resolve, reject) => {
100→    const timeout = setTimeout(() => {
101→      proc.kill();
102→      reject(new Error(`OpenCode server did not start within ${SERVER_START_TIMEOUT_MS}ms`));
103→    }, SERVER_START_TIMEOUT_MS);
104→
105→    let output = "";
106→
107→    proc.stdout?.on("data", (chunk: Buffer) => {
108→      output += chunk.toString();
109→      const lines = output.split("\n");
110→      for (const line of lines) {
111→        if (line.startsWith("opencode server listening")) {
112→          const match = line.match(/on\s+(https?:\/\/[^\s]+)/);
113→          if (!match) {
114→            clearTimeout(timeout);
115→            proc.kill();
116→            reject(new Error(`Failed to parse server URL from: ${line}`));
117→            return;
118→          }
119→          clearTimeout(timeout);
120→          resolve({ proc, url: match[1] });
121→          return;
122→        }
123→      }
124→    });
125→
126→    proc.stderr?.on("data", (chunk: Buffer) => {
127→      output += chunk.toString();
128→    });
129→
130→    proc.on("exit", (code) => {
131→      clearTimeout(timeout);
132→      reject(new Error(`OpenCode server exited with code ${code}\n${output}`));
133→    });
134→
135→    proc.on("error", (err) => {
136→      clearTimeout(timeout);
137→      reject(err);
138→    });
139→  });
140→}
141→
142→// ---------------------------------------------------------------------------
143→// spawnOpenCode — production implementation
144→// ---------------------------------------------------------------------------
145→
146→export async function spawnOpenCode(
147→  config: OpencodeConfig,
148→  worktreePath: string,
149→): Promise<OpenCodeHandle> {
150→  const hostname = "127.0.0.1";
151→  const port = await findFreePort();
152→  const sdkConfig = toSdkConfig(config);
153→
154→  const abortController = new AbortController();
155→
156→  const { proc, url } = await startServerProcess(
157→    port,
158→    hostname,
159→    sdkConfig,
160→    worktreePath,
161→    abortController.signal,
162→  );
163→
164→  const client = createOpencodeClient({ baseUrl: url });
165→
166→  const response = await client.session.create({
167→    body: { title: "Brain orchestrator session" },
168→  });
169→
170→  if (response.error) {
171→    abortController.abort();
172→    proc.kill();
173→    throw new Error(`Failed to create OpenCode session: ${JSON.stringify(response.error)}`);
174→  }
175→
176→  const sessionId = response.data.id;
177→
178→  return {
179→    sessionId,
180→    abort: () => {
181→      try {
182→        client.session.abort({ path: { id: sessionId } }).catch(() => {});
183→      } finally {
184→        abortController.abort();
185→        proc.kill();
186→      }
187→    },
188→  };
189→}
