  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { OpencodeConfig } from "./config-builder";
  3→import { buildOpencodeConfig } from "./config-builder";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus } from "./types";
  8→
  9→// ---------------------------------------------------------------------------
 10→// Types — exported for tests
 11→// ---------------------------------------------------------------------------
 12→
 13→export type OpenCodeHandle = {
 14→  sessionId: string;
 15→  abort: () => void;
 16→};
 17→
 18→export type SessionDeps = {
 19→  surreal: Surreal;
 20→  shellExec: ShellExec;
 21→  brainBaseUrl: string;
 22→  spawnOpenCode?: (
 23→    config: OpencodeConfig,
 24→    worktreePath: string,
 25→  ) => Promise<OpenCodeHandle>;
 26→};
 27→
 28→export type SessionErrorCode =
 29→  | "TASK_NOT_FOUND"
 30→  | "TASK_NOT_ASSIGNABLE"
 31→  | "AGENT_ALREADY_ACTIVE"
 32→  | "WORKSPACE_MISMATCH"
 33→  | "MISSING_TASK_ID"
 34→  | "WORKTREE_ERROR"
 35→  | "SESSION_NOT_FOUND"
 36→  | "SESSION_ERROR";
 37→
 38→export type SessionError = {
 39→  code: SessionErrorCode;
 40→  message: string;
 41→  httpStatus: number;
 42→};
 43→
 44→export type SessionResult<T> =
 45→  | { ok: true; value: T }
 46→  | { ok: false; error: SessionError };
 47→
 48→export type OrchestratorSessionResult = SessionResult<{
 49→  agentSessionId: string;
 50→  streamId: string;
 51→  worktreeBranch: string;
 52→}>;
 53→
 54→export type SessionStatusResult = SessionResult<{
 55→  orchestratorStatus: OrchestratorStatus;
 56→  worktreeBranch?: string;
 57→  worktreePath?: string;
 58→  lastEventAt?: string;
 59→  startedAt?: string;
 60→  error?: string;
 61→}>;
 62→
 63→export type AbortSessionResult = SessionResult<{
 64→  aborted: boolean;
 65→  sessionId: string;
 66→}>;
 67→
 68→export type AcceptSessionResult = SessionResult<{
 69→  accepted: boolean;
 70→  sessionId: string;
 71→}>;
 72→
 73→export type ReviewResult = SessionResult<{
 74→  taskTitle: string;
 75→  diff: import("./worktree-manager").DiffResult;
 76→  session: {
 77→    orchestratorStatus: string;
 78→    worktreeBranch?: string;
 79→    startedAt?: string;
 80→    lastEventAt?: string;
 81→    toolCallCount?: number;
 82→    filesEdited?: number;
 83→  };
 84→}>;
 85→
 86→export type RejectSessionResult = SessionResult<{
 87→  rejected: boolean;
 88→  continuing: boolean;
 89→}>;
 90→
 91→// ---------------------------------------------------------------------------
 92→// In-memory handle registry — maps agentSessionId to OpenCodeHandle
 93→// ---------------------------------------------------------------------------
 94→
 95→const handleRegistry = new Map<string, OpenCodeHandle>();
 96→
 97→// Exported for testing cleanup
 98→export function clearHandleRegistry(): void {
 99→  handleRegistry.clear();
100→}
101→
102→// ---------------------------------------------------------------------------
103→// Pure helpers
104→// ---------------------------------------------------------------------------
105→
106→function sessionNotFound(sessionId: string): SessionError {
107→  return {
108→    code: "SESSION_NOT_FOUND",
109→    message: `Session not found: ${sessionId}`,
110→    httpStatus: 404,
111→  };
112→}
113→
114→function worktreeError(message: string): SessionError {
115→  return {
116→    code: "WORKTREE_ERROR",
117→    message,
118→    httpStatus: 500,
119→  };
120→}
121→
122→function fromAssignmentError(error: AssignmentError): SessionError {
123→  return {
124→    code: error.code as SessionErrorCode,
125→    message: error.message,
126→    httpStatus: error.httpStatus,
127→  };
128→}
129→
130→type SessionLookup =
131→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
132→  | { ok: false; error: SessionError };
133→
134→async function lookupSession(
135→  surreal: Surreal,
136→  sessionId: string,
137→): Promise<SessionLookup> {
138→  const record = new RecordId("agent_session", sessionId);
139→  const session = await surreal.select<SessionRow>(record);
140→  if (!session) {
141→    return { ok: false, error: sessionNotFound(sessionId) };
142→  }
143→  if (!session.orchestrator_status) {
144→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
145→  }
146→  const status = session.orchestrator_status as OrchestratorStatus;
147→  return { ok: true, session, record, status };
148→}
149→
