151→  return `stream-${sessionId}`;
152→}
153→
154→function slugFromTitle(title: string): string {
155→  return title
156→    .toLowerCase()
157→    .replace(/[^a-z0-9]+/g, "-")
158→    .replace(/^-|-$/g, "")
159→    .slice(0, 50);
160→}
