162→// ---------------------------------------------------------------------------
163→// Session row shape (DB query result)
164→// ---------------------------------------------------------------------------
165→
166→type SessionRow = {
167→  id: RecordId<"agent_session", string>;
168→  orchestrator_status?: string;
169→  worktree_branch?: string;
170→  worktree_path?: string;
171→  started_at?: string;
172→  last_event_at?: string;
173→  task_id?: RecordId<"task", string>;
174→  workspace?: RecordId<"workspace", string>;
175→  error?: string;
176→};
177→
178→// ---------------------------------------------------------------------------
179→// createOrchestratorSession
180→// ---------------------------------------------------------------------------
181→
182→type CreateSessionInput = {
183→  surreal: Surreal;
184→  shellExec: ShellExec;
185→  brainBaseUrl: string;
186→  workspaceId: string;
187→  taskId: string;
188→  authToken: string;
189→  spawnOpenCode?: (
190→    config: OpencodeConfig,
191→    worktreePath: string,
192→  ) => Promise<OpenCodeHandle>;
193→  validateAssignment: (
194→    surreal: Surreal,
195→    workspaceId: string,
196→    taskId: string,
197→  ) => Promise<AssignmentResult>;
198→  createAgentSession: (input: {
199→    surreal: Surreal;
200→    agent: string;
201→    workspaceRecord: RecordId<"workspace", string>;
202→    taskId?: string;
203→  }) => Promise<{ session_id: string }>;
204→};
205→
206→export async function createOrchestratorSession(
207→  input: CreateSessionInput,
208→): Promise<OrchestratorSessionResult> {
209→  // 1. Validate assignment eligibility
210→  const assignmentResult = await input.validateAssignment(
211→    input.surreal,
212→    input.workspaceId,
213→    input.taskId,
214→  );
215→
216→  if (!assignmentResult.ok) {
217→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
218→  }
219→
220→  const { validation } = assignmentResult;
221→  const taskSlug = slugFromTitle(validation.title);
222→  const repoRoot = validation.repoPath;
223→
224→  // 2. Create worktree
225→  const worktreeResult = await createWorktree(
226→    input.shellExec,
227→    repoRoot,
228→    taskSlug,
229→  );
230→
231→  if (!worktreeResult.ok) {
232→    return {
233→      ok: false,
234→      error: worktreeError(worktreeResult.error.message),
235→    };
236→  }
237→
238→  const { branchName, worktreePath } = worktreeResult.value;
239→
240→  // 3. Create agent_session record
241→  const { session_id: agentSessionId } = await input.createAgentSession({
242→    surreal: input.surreal,
243→    agent: "opencode",
244→    workspaceRecord: validation.workspaceRecord,
245→    taskId: input.taskId,
246→  });
247→
248→  const streamId = generateStreamId(agentSessionId);
249→
250→  // 4. Build config and spawn OpenCode
251→  const config = buildOpencodeConfig({
252→    brainBaseUrl: input.brainBaseUrl,
253→    workspaceId: input.workspaceId,
254→    authToken: input.authToken,
255→  });
256→
257→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
258→  let handle: OpenCodeHandle;
259→  try {
260→    handle = await spawnFn(config, worktreePath);
261→  } catch (err) {
262→    // Rollback: remove worktree and delete agent_session on spawn failure
263→    await removeWorktree(input.shellExec, repoRoot, branchName);
264→    const sessionRecord = new RecordId("agent_session", agentSessionId);
265→    await input.surreal.delete(sessionRecord);
266→    return {
267→      ok: false,
268→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
269→    };
270→  }
271→
272→  // 5. Register handle for later abort
273→  handleRegistry.set(agentSessionId, handle);
274→
275→  // 6. Update agent_session with orchestrator fields
276→  const sessionRecord = new RecordId("agent_session", agentSessionId);
277→  await input.surreal.update(sessionRecord).merge({
278→    orchestrator_status: "spawning" as OrchestratorStatus,
279→    worktree_branch: branchName,
280→    worktree_path: worktreePath,
281→    opencode_session_id: handle.sessionId,
282→    stream_id: streamId,
283→  });
284→
285→  return {
286→    ok: true,
287→    value: {
288→      agentSessionId,
289→      streamId,
290→      worktreeBranch: branchName,
291→    },
292→  };
293→}
294→
295→// Default spawn -- placeholder for production use
296→async function defaultSpawnOpenCode(
297→  _config: OpencodeConfig,
298→  _worktreePath: string,
299→): Promise<OpenCodeHandle> {
300→  throw new Error(
301→    "spawnOpenCode not provided -- must be injected for production use",
302→  );
303→}
