305→// ---------------------------------------------------------------------------
306→// getOrchestratorSessionStatus
307→// ---------------------------------------------------------------------------
308→
309→type GetStatusInput = {
310→  surreal: Surreal;
311→  sessionId: string;
312→};
313→
314→export async function getOrchestratorSessionStatus(
315→  input: GetStatusInput,
316→): Promise<SessionStatusResult> {
317→  const lookup = await lookupSession(input.surreal, input.sessionId);
318→  if (!lookup.ok) {
319→    return { ok: false, error: lookup.error };
320→  }
321→  const { session } = lookup;
322→
323→  return {
324→    ok: true,
325→    value: {
326→      orchestratorStatus: lookup.status,
327→      ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
328→      ...(session.worktree_path ? { worktreePath: session.worktree_path } : {}),
329→      ...(session.started_at ? { startedAt: session.started_at } : {}),
330→      ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
