336→// ---------------------------------------------------------------------------
337→// abortOrchestratorSession
338→// ---------------------------------------------------------------------------
339→
340→type AbortSessionInput = {
341→  surreal: Surreal;
342→  shellExec: ShellExec;
343→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
344→  sessionId: string;
345→  endAgentSession: (input: {
346→    surreal: Surreal;
347→    workspaceRecord: RecordId<"workspace", string>;
348→    sessionId: string;
349→    summary: string;
350→  }) => Promise<{ session_id: string; ended: boolean }>;
351→};
352→
353→export async function abortOrchestratorSession(
354→  input: AbortSessionInput,
355→): Promise<AbortSessionResult> {
356→  const lookup = await lookupSession(input.surreal, input.sessionId);
357→  if (!lookup.ok) {
358→    return { ok: false, error: lookup.error };
359→  }
360→  const { session, record: sessionRecord } = lookup;
361→
362→  // 1. Kill the OpenCode process if handle exists
363→  const handle = handleRegistry.get(input.sessionId);
364→  if (handle) {
365→    handle.abort();
366→    handleRegistry.delete(input.sessionId);
367→  }
368→
369→  // 2. Update orchestrator_status to aborted
370→  await input.surreal.update(sessionRecord).merge({
371→    orchestrator_status: "aborted" as OrchestratorStatus,
372→  });
373→
374→  // 3. Remove worktree if branch name exists
375→  if (session.worktree_branch && session.workspace) {
376→    const repoRoot = await input.resolveRepoRoot(session.workspace as RecordId<"workspace", string>);
377→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
378→  }
379→
380→  // 4. Return task to ready
381→  if (session.task_id) {
382→    await input.surreal.update(session.task_id).merge({
383→      status: "ready",
384→      updated_at: new Date(),
385→    });
386→  }
387→
388→  // 5. End the agent session
389→  if (!session.workspace) {
390→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
391→  }
392→  await input.endAgentSession({
393→    surreal: input.surreal,
394→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
395→    sessionId: input.sessionId,
396→    summary: "Session aborted",
397→  });
398→
399→  return {
400→    ok: true,
401→    value: {
402→      aborted: true,
403→      sessionId: input.sessionId,
404→    },
405→  };
406→}
407→
408→// ---------------------------------------------------------------------------
409→// acceptOrchestratorSession
410→// ---------------------------------------------------------------------------
411→
412→type AcceptSessionInput = {
413→  surreal: Surreal;
414→  sessionId: string;
415→  summary: string;
416→  endAgentSession: (input: {
417→    surreal: Surreal;
418→    workspaceRecord: RecordId<"workspace", string>;
419→    sessionId: string;
420→    summary: string;
421→  }) => Promise<{ session_id: string; ended: boolean }>;
422→};
423→
424→export async function acceptOrchestratorSession(
425→  input: AcceptSessionInput,
426→): Promise<AcceptSessionResult> {
427→  const lookup = await lookupSession(input.surreal, input.sessionId);
428→  if (!lookup.ok) {
429→    return { ok: false, error: lookup.error };
430→  }
431→  const { session, record: sessionRecord, status } = lookup;
432→
433→  if (!ACCEPTABLE_STATUSES.has(status)) {
434→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
435→  }
436→
437→  // 1. Update orchestrator_status to completed
438→  await input.surreal.update(sessionRecord).merge({
439→    orchestrator_status: "completed" as OrchestratorStatus,
440→  });
441→
442→  // 2. Mark task as done
443→  if (session.task_id) {
444→    await input.surreal.update(session.task_id).merge({
445→      status: "done",
446→      updated_at: new Date(),
447→    });
448→  }
449→
450→  // 3. Clean up handle registry
451→  handleRegistry.delete(input.sessionId);
452→
453→  // 4. End the agent session
454→  if (!session.workspace) {
455→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
456→  }
457→  await input.endAgentSession({
458→    surreal: input.surreal,
459→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
460→    sessionId: input.sessionId,
461→    summary: input.summary,
462→  });
463→
464→  return {
465→    ok: true,
466→    value: {
467→      accepted: true,
468→      sessionId: input.sessionId,
469→    },
470→  };
471→}
