473→// ---------------------------------------------------------------------------
474→// State guard helpers
475→// ---------------------------------------------------------------------------
476→
477→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
478→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
479→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
480→
481→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
482→  return {
483→    code: "SESSION_ERROR",
484→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
485→    httpStatus: 409,
486→  };
487→}
488→
489→function sessionAborted(sessionId: string): SessionError {
490→  return {
491→    code: "SESSION_ERROR",
492→    message: `Session ${sessionId} has been aborted`,
493→    httpStatus: 409,
494→  };
495→}
