557→// ---------------------------------------------------------------------------
558→// rejectOrchestratorSession
559→// ---------------------------------------------------------------------------
560→
561→type RejectSessionInput = {
562→  surreal: Surreal;
563→  sessionId: string;
564→  feedback: string;
565→};
566→
567→export async function rejectOrchestratorSession(
568→  input: RejectSessionInput,
569→): Promise<RejectSessionResult> {
570→  const lookup = await lookupSession(input.surreal, input.sessionId);
571→  if (!lookup.ok) {
572→    return { ok: false, error: lookup.error };
573→  }
574→  const { session, record: sessionRecord, status } = lookup;
575→
576→  if (!REJECTABLE_STATUSES.has(status)) {
577→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
578→  }
579→
580→  // 1. Update session status to active (agent resumes work)
581→  await input.surreal.update(sessionRecord).merge({
582→    orchestrator_status: "active" as OrchestratorStatus,
583→    last_feedback: input.feedback,
584→  });
585→
586→  // 2. Return task to in_progress
587→  if (session.task_id) {
588→    await input.surreal.update(session.task_id).merge({
589→      status: "in_progress",
590→      updated_at: new Date(),
591→    });
592→  }
593→
594→  return {
595→    ok: true,
596→    value: {
597→      rejected: true,
598→      continuing: true,
599→    },
600→  };
601→}
