244→// ---------------------------------------------------------------------------
245→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
246→// ---------------------------------------------------------------------------
247→
248→export type OrchestratorWiringDeps = {
249→  surreal: import("surrealdb").Surreal;
250→  shellExec: import("./worktree-manager").ShellExec;
251→  brainBaseUrl: string;
252→  sseRegistry?: SseRegistry;
253→};
254→
255→export function wireOrchestratorRoutes(
256→  wiringDeps: OrchestratorWiringDeps,
257→): {
258→  assign: RouteHandler;
259→  status: RouteHandler;
260→  accept: RouteHandler;
261→  abort: RouteHandler;
262→  review: RouteHandler;
263→  reject: RouteHandler;
264→  stream?: RouteHandler;
265→} {
266→  // Lazy imports to keep module boundary clean
267→  const lifecycleImport = import("./session-lifecycle");
268→  const queriesImport = import("../mcp/mcp-queries");
269→  const guardImport = import("./assignment-guard");
270→
271→  // Helper: resolve repo_path from workspace record
272→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
273→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
274→      `SELECT repo_path FROM $ws;`,
275→      { ws: workspaceRecord },
276→    );
277→    const repoPath = rows[0]?.repo_path;
278→    if (!repoPath) {
279→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
280→    }
281→    return repoPath;
282→  };
283→
284→  // Use mock spawn for acceptance tests, production spawn otherwise
285→  const spawnOpenCodeImport = process.env.ORCHESTRATOR_MOCK_OPENCODE === "true"
286→    ? Promise.resolve({
287→        spawnOpenCode: async () => ({
288→          sessionId: crypto.randomUUID(),
289→          abort: () => {},
290→        }),
291→      })
292→    : import("./spawn-opencode");
293→
294→  const routeDeps: OrchestratorRouteDeps = {
295→    createSession: async (workspaceId, taskId, authToken) => {
296→      const [lifecycle, queries, guard, { spawnOpenCode }] = await Promise.all([
297→        lifecycleImport,
298→        queriesImport,
299→        guardImport,
300→        spawnOpenCodeImport,
301→      ]);
302→      return lifecycle.createOrchestratorSession({
303→        surreal: wiringDeps.surreal,
304→        shellExec: wiringDeps.shellExec,
305→        brainBaseUrl: wiringDeps.brainBaseUrl,
306→        workspaceId,
307→        taskId,
308→        authToken,
309→        validateAssignment: guard.validateAssignment,
310→        createAgentSession: queries.createAgentSession,
311→        spawnOpenCode,
312→      });
313→    },
314→
315→    getSessionStatus: async (sessionId) => {
316→      const lifecycle = await lifecycleImport;
317→      return lifecycle.getOrchestratorSessionStatus({
318→        surreal: wiringDeps.surreal,
319→        sessionId,
320→      });
321→    },
322→
323→    abortSession: async (sessionId) => {
324→      const [lifecycle, queries] = await Promise.all([
325→        lifecycleImport,
326→        queriesImport,
327→      ]);
328→      return lifecycle.abortOrchestratorSession({
329→        surreal: wiringDeps.surreal,
330→        shellExec: wiringDeps.shellExec,
331→        resolveRepoRoot,
332→        sessionId,
333→        endAgentSession: queries.endAgentSession,
334→      });
335→    },
336→
337→    acceptSession: async (sessionId, summary) => {
338→      const [lifecycle, queries] = await Promise.all([
339→        lifecycleImport,
340→        queriesImport,
341→      ]);
342→      return lifecycle.acceptOrchestratorSession({
343→        surreal: wiringDeps.surreal,
344→        sessionId,
345→        summary,
346→        endAgentSession: queries.endAgentSession,
347→      });
348→    },
349→
350→    getReview: async (sessionId) => {
351→      const [lifecycle, worktreeManager] = await Promise.all([
352→        lifecycleImport,
353→        import("./worktree-manager"),
354→      ]);
355→      return lifecycle.getOrchestratorReview({
356→        surreal: wiringDeps.surreal,
357→        sessionId,
358→        resolveRepoRoot,
359→        getDiff: (repoRoot: string, branchName: string) =>
360→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
361→        getTaskTitle: async (taskId: string) => {
362→          const { RecordId } = await import("surrealdb");
363→          const taskRecord = new RecordId("task", taskId);
364→          const rows = (await wiringDeps.surreal.query(
365→            `SELECT title FROM $task;`,
366→            { task: taskRecord },
367→          )) as Array<Array<{ title: string }>>;
368→          return rows[0]?.[0]?.title ?? "";
369→        },
370→      });
371→    },
372→
373→    rejectSession: async (sessionId, feedback) => {
374→      const lifecycle = await lifecycleImport;
375→      return lifecycle.rejectOrchestratorSession({
376→        surreal: wiringDeps.surreal,
377→        sessionId,
378→        feedback,
379→      });
380→    },
381→  };
382→
383→  const handlers = createOrchestratorRouteHandlers(routeDeps);
384→
385→  const streamHandler = wiringDeps.sseRegistry
386→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
387→    : undefined;
388→
389→  return {
390→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
391→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
392→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
393→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
394→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
395→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
396→    ...(streamHandler
397→      ? { stream: withRequestLogging("orchestrator.stream", "GET", streamHandler.stream) }
398→      : {}),
399→  };
400→}
