 1→// ---------------------------------------------------------------------------
 2→// OpenCode config builder — pure function, no side effects
 3→// ---------------------------------------------------------------------------
 4→
 5→export type OpencodeConfig = {
 6→  mcpServers: Record<string, { url: string; headers: Record<string, string> }>;
 7→  model: { provider: string; model: string };
 8→  permissions: { autoApprove: string[] };
 9→};
10→
11→export type ConfigInput = {
12→  brainBaseUrl: string;
13→  workspaceId: string;
14→  authToken: string;
15→  modelProvider?: string;
16→  modelName?: string;
17→};
18→
19→const DEFAULT_MODEL_PROVIDER = "anthropic";
20→const DEFAULT_MODEL_NAME = "claude-sonnet-4-20250514";
21→const AUTO_APPROVE_PERMISSIONS = ["read", "write", "edit", "bash"];
22→
23→function stripTrailingSlash(url: string): string {
24→  return url.endsWith("/") ? url.slice(0, -1) : url;
25→}
26→
27→function buildMcpUrl(baseUrl: string, workspaceId: string): string {
28→  return `${stripTrailingSlash(baseUrl)}/api/mcp/${workspaceId}`;
29→}
30→
31→function buildAuthHeaders(authToken: string): Record<string, string> {
32→  return { Authorization: `Bearer ${authToken}` };
33→}
34→
35→export function buildOpencodeConfig(input: ConfigInput): OpencodeConfig {
36→  return {
37→    mcpServers: {
38→      brain: {
39→        url: buildMcpUrl(input.brainBaseUrl, input.workspaceId),
40→        headers: buildAuthHeaders(input.authToken),
41→      },
42→    },
43→    model: {
44→      provider: input.modelProvider ?? DEFAULT_MODEL_PROVIDER,
45→      model: input.modelName ?? DEFAULT_MODEL_NAME,
46→    },
47→    permissions: {
48→      autoApprove: AUTO_APPROVE_PERMISSIONS,
49→    },
50→  };
51→}
