  1→/**
  2→ * useAgentSession -- SSE subscription hook for agent session state.
  3→ *
  4→ * Opens an EventSource when given an active sessionId + streamUrl.
  5→ * Exposes AgentSessionState: status, filesChanged, startedAt,
  6→ * stallWarning, connectionError.
  7→ *
  8→ * Pure core: reduceAgentSessionEvent handles all state transitions.
  9→ * Effect boundary: useEffect manages EventSource lifecycle + stall timer.
 10→ */
 11→
 12→import { useCallback, useEffect, useRef, useState } from "react";
 13→import type {
 14→  AgentStatusEvent,
 15→  AgentFileChangeEvent,
 16→  AgentStallWarningEvent,
 17→} from "../../shared/contracts";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Types
 21→// ---------------------------------------------------------------------------
 22→
 23→export type AgentSessionStatus =
 24→  | "spawning"
 25→  | "active"
 26→  | "idle"
 27→  | "completed"
 28→  | "aborted"
 29→  | "error";
 30→
 31→export type AgentSessionState = {
 32→  status: AgentSessionStatus;
 33→  filesChanged: number;
 34→  startedAt: string;
 35→  lastEventAt?: string;
 36→  stallWarning?: { lastEventAt: string; stallDurationSeconds: number };
 37→  error?: string;
 38→  connectionError?: string;
 39→};
 40→
 41→// Events the reducer handles (subset of StreamEvent relevant to agent sessions)
 42→type AgentEvent = AgentStatusEvent | AgentFileChangeEvent | AgentStallWarningEvent;
 43→
 44→// ---------------------------------------------------------------------------
 45→// Constants
 46→// ---------------------------------------------------------------------------
 47→
 48→export const STALL_TIMEOUT_MS = 30_000;
 49→
 50→// ---------------------------------------------------------------------------
 51→// Pure core: state reducer
 52→// ---------------------------------------------------------------------------
 53→
 54→export function createInitialState(startedAt: string): AgentSessionState {
 55→  return {
 56→    status: "spawning",
 57→    filesChanged: 0,
 58→    startedAt,
 59→  };
 60→}
 61→
 62→export function isTerminalStatus(status: AgentSessionStatus): boolean {
 63→  return status === "completed" || status === "aborted" || status === "error";
 64→}
 65→
 66→export function reduceAgentSessionEvent(
 67→  state: AgentSessionState,
 68→  event: AgentEvent,
 69→): AgentSessionState {
 70→  const now = new Date().toISOString();
 71→
 72→  switch (event.type) {
 73→    case "agent_status":
 74→      return {
 75→        ...state,
 76→        status: event.status,
 77→        lastEventAt: now,
 78→        stallWarning: undefined,
 79→        error: event.error,
 80→      };
 81→
 82→    case "agent_file_change":
 83→      return {
 84→        ...state,
 85→        filesChanged: state.filesChanged + 1,
 86→        lastEventAt: now,
 87→        stallWarning: undefined,
 88→      };
 89→
 90→    case "agent_stall_warning":
 91→      return {
 92→        ...state,
 93→        lastEventAt: now,
 94→        stallWarning: {
 95→          lastEventAt: event.lastEventAt,
 96→          stallDurationSeconds: event.stallDurationSeconds,
 97→        },
 98→      };
 99→  }
100→}
101→
102→// ---------------------------------------------------------------------------
103→// Hook return type
104→// ---------------------------------------------------------------------------
105→
106→export type UseAgentSessionReturn = {
107→  state: AgentSessionState;
108→  close: () => void;
109→};
110→
111→// ---------------------------------------------------------------------------
112→// Hook: effect boundary (EventSource lifecycle + stall timer)
113→// ---------------------------------------------------------------------------
114→
115→export function useAgentSession(
116→  streamUrl: string | undefined,
117→  startedAt: string,
118→): UseAgentSessionReturn {
119→  const [state, setState] = useState<AgentSessionState>(() =>
120→    createInitialState(startedAt),
121→  );
122→  const eventSourceRef = useRef<EventSource | undefined>(undefined);
123→  const stallTimerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
124→
125→  // Timer lifecycle: clearStallTimer is stable (no deps). resetStallTimer depends only on
126→  // clearStallTimer, so it is also stable. Both use stallTimerRef (a ref, not state) to avoid
127→  // stale closures. setState updater form ensures state reads are always current.
128→  const clearStallTimer = useCallback(() => {
129→    if (stallTimerRef.current !== undefined) {
130→      clearTimeout(stallTimerRef.current);
131→      stallTimerRef.current = undefined;
132→    }
133→  }, []);
134→
135→  const resetStallTimer = useCallback(() => {
136→    clearStallTimer();
137→    stallTimerRef.current = setTimeout(() => {
138→      setState((prev) => ({
139→        ...prev,
140→        stallWarning: {
141→          lastEventAt: prev.lastEventAt ?? prev.startedAt,
142→          stallDurationSeconds: STALL_TIMEOUT_MS / 1000,
143→        },
144→      }));
145→    }, STALL_TIMEOUT_MS);
146→  }, [clearStallTimer]);
147→
148→  useEffect(() => {
149→    if (!streamUrl) return;
150→
151→    const eventSource = new EventSource(streamUrl);
152→    eventSourceRef.current = eventSource;
153→
154→    function handleEvent(eventType: string, rawData: string) {
155→      try {
156→        const data = JSON.parse(rawData);
157→        const event: AgentEvent = { ...data, type: eventType };
158→        setState((prev) => reduceAgentSessionEvent(prev, event));
159→        resetStallTimer();
160→
161→        // Close on terminal status
162→        if (eventType === "agent_status" && isTerminalStatus(data.status)) {
163→          eventSource.close();
164→          clearStallTimer();
165→        }
166→      } catch {
167→        // Malformed event data -- ignore
168→      }
169→    }
170→
171→    eventSource.addEventListener("agent_status", (e) =>
172→      handleEvent("agent_status", e.data),
173→    );
174→    eventSource.addEventListener("agent_file_change", (e) =>
175→      handleEvent("agent_file_change", e.data),
176→    );
177→    eventSource.addEventListener("agent_stall_warning", (e) =>
178→      handleEvent("agent_stall_warning", e.data),
179→    );
180→
181→    eventSource.onerror = () => {
182→      eventSource.close();
183→      clearStallTimer();
184→      setState((prev) => ({
185→        ...prev,
186→        status: "error",
187→        connectionError: "Connection lost",
188→      }));
189→    };
190→
191→    // Start stall timer
192→    resetStallTimer();
193→
194→    return () => {
195→      eventSource.close();
196→      eventSourceRef.current = undefined;
197→      clearStallTimer();
198→    };
199→  }, [streamUrl, resetStallTimer, clearStallTimer]);
200→
201→  const close = useCallback(() => {
202→    if (eventSourceRef.current) {
203→      eventSourceRef.current.close();
204→      eventSourceRef.current = undefined;
205→    }
206→    clearStallTimer();
207→  }, [clearStallTimer]);
208→
209→  return { state, close };
210→}
211→

