 58→  if (input.rejectStatus === "success") {
 59→    return {
 60→      viewState: "rejected",
 61→      taskTitle: input.reviewData?.taskTitle,
 62→      acceptDisabled: true,
 63→      rejectSubmitDisabled: true,
 64→    };
 65→  }
 66→
 67→  // Loading states
 68→  if (input.fetchStatus === "idle" || input.fetchStatus === "pending") {
 69→    return {
 70→      viewState: "loading",
 71→      acceptDisabled: true,
 72→      rejectSubmitDisabled: true,
 73→    };
 74→  }
 75→
 76→  // Error state
 77→  if (input.fetchStatus === "error") {
 78→    return {
 79→      viewState: "error",
 80→      errorMessage: input.fetchError,
 81→      acceptDisabled: true,
 82→      rejectSubmitDisabled: true,
 83→    };
 84→  }
 85→
 86→  // Loaded with review data
 87→  const data = input.reviewData;
 88→  const isMutating = input.acceptStatus === "pending" || input.rejectStatus === "pending";
 89→
 90→  return {
 91→    viewState: "review",
 92→    taskTitle: data?.taskTitle,
 93→    agentSummary: data?.summary,
 94→    rawDiff: data?.diff.rawDiff,
 95→    diffStats: data ? {
 96→      filesChanged: data.diff.stats.filesChanged,
 97→      insertions: data.diff.stats.insertions,
 98→      deletions: data.diff.stats.deletions,
 99→    } : undefined,
100→    sessionMeta: data ? {
101→      startedAt: data.session.startedAt,
102→      lastEventAt: data.session.lastEventAt,
103→      decisionsCount: data.session.decisionsCount,
104→      questionsCount: data.session.questionsCount,
105→      observationsCount: data.session.observationsCount,
106→    } : undefined,
107→    acceptDisabled: isMutating,
108→    rejectSubmitDisabled: isMutating || input.rejectFeedback.trim().length === 0,
109→  };
110→}
