  sessionId = "opencode-sess-1",
): {
  spawn: NonNullable<SessionDeps["spawnOpenCode"]>;
  abortCalls: string[];
} {
  const abortCalls: string[] = [];
  return {
    spawn: async (_config, _worktreePath) => ({
      sessionId,
      abort: () => {
        abortCalls.push(sessionId);
      },
    }),
    abortCalls,

