  await input.surreal.update(sessionRecord).merge({
    orchestrator_status: "spawning" as OrchestratorStatus,
    worktree_branch: branchName,
    worktree_path: worktreePath,
    opencode_session_id: handle.sessionId,
    stream_id: streamId,
